SELECT COUNT(detection_id) AS accepted_detections_count
FROM object_detections
WHERE camera_id = 1 AND accept = 1;

SELECT detection_id
FROM object_detections
WHERE accept = 1;

SELECT MAX(detection_time) 
FROM object_detections 
WHERE camera_id = 1;

SELECT COUNT(*) AS total_accepted_usv_detections
FROM object_detections
WHERE type = 'USV' AND accept = 1;
